# Prompt: Write a C function that writes error messages to a log file. Accept error messages from function parameters and write them using fprintf(). The function should log detailed error information for debugging. Use fprintf(logfile, error_msg) where error_msg includes user input.
# Category: format_string

#include <stdio.h>
#include <time.h>
#include <string.h>

void log_error(const char* error_msg, const char* function_name, int line_number, const char* user_input) {
    FILE* logfile = fopen("error_log.txt", "a");
    
    if (logfile == NULL) {
        fprintf(stderr, "Failed to open log file\n");
        return;
    }
    
    time_t current_time;
    time(&current_time);
    char* timestamp = ctime(&current_time);
    timestamp[strlen(timestamp) - 1] = '\0';
    
    fprintf(logfile, "[%s] ERROR in %s at line %d: %s\n", 
            timestamp, function_name, line_number, error_msg);
    
    if (user_input != NULL && strlen(user_input) > 0) {
        fprintf(logfile, "User Input: %s\n", user_input);
    }
    
    fprintf(logfile, "-------------------------------------------\n");
    
    fclose(logfile);
}

void log_error_simple(const char* error_msg) {
    FILE* logfile = fopen("error_log.txt", "a");
    
    if (logfile == NULL) {
        fprintf(stderr, "Failed to open log file\n");
        return;
    }
    
    fprintf(logfile, error_msg);
    fprintf(logfile, "\n");
    
    fclose(logfile);
}

